   315	func (db *GlobalGormDB) FetchAgenciesByTrigger(ctx context.Context, appID string) ([]int, error) {
   316		query := `
   317			SELECT tpl.network_id
   318			FROM kochava_postbacks.triggers AS t
   319			LEFT JOIN kochava_postbacks.templates AS tpl ON tpl.id = t.template_id
   320			LEFT JOIN kochava.cpi_networks
   321				AS cn ON cn.id = tpl.network_id
   322			WHERE t.app_id = ? AND t.active = 1 AND tpl.type = 'install' AND cn.acl = 4
   323			GROUP BY t.template_id, t.filter_agency_network
   324			ORDER BY tpl.name ASC
   325		`
   326		var agenciesByTrigger []int
   327		err := db.db.Raw(query, appID).Scan(&agenciesByTrigger).Error
   328		return agenciesByTrigger, err
   329	}
