   331	// FetchTriggers returns an app's install triggers, scoped by agency network.
   332	//
   333	// The caller (get_agency_triggers) passes the agency_network_ids it wants to view as
   334	// ids. Each agency configures its own trigger row (same app_id/template_id, distinct
   335	// filter_agency_network), so the scope MUST filter on filter_agency_network — not on
   336	// filter_network. When no agency ids are supplied we fall back to the advertiser scope
   337	// (filter_agency_network = 0). Without this, agency triggers exist in the triggers table
   338	// but never come back to the UI, and switching agencies surfaces the wrong agency's rows.
   339	func (db *GlobalGormDB) FetchTriggers(ctx context.Context, appID string, ids []string) ([]models.Trigger, error) {
   340		executeParams := []any{appID}
   341	
   342		// Sanitize the agency ids before scoping. Callers build ids via strings.Split, which
   343		// can yield empty/whitespace entries (e.g. a trailing comma). An empty string bound to
   344		// an INT comparison coerces to 0 in MySQL, which would pull advertiser-scoped rows
   345		// (filter_agency_network = 0) into an agency-scoped request and break isolation. Parse
   346		// each id to int and drop anything invalid so only real agency network IDs are matched.
   347		var placeholders []string
   348		for _, id := range ids {
   349			agencyID, err := strconv.Atoi(strings.TrimSpace(id))
   350			if err != nil {
   351				continue
   352			}
   353			placeholders = append(placeholders, "?")
   354			executeParams = append(executeParams, agencyID)
   355		}
   356	
   357		var agencyScope string
   358		if len(placeholders) > 0 {
   359			agencyScope = fmt.Sprintf("t.filter_agency_network IN (%s)", strings.Join(placeholders, ", "))
   360		} else {
   361			// No valid agency requested: advertiser-level triggers only.
   362			agencyScope = "t.filter_agency_network = 0"
   363		}
   364	
   365		query := fmt.Sprintf(`
   366			SELECT t.id, n.name, t.filter_network, t.title, t.template_id, t.active, t.filter_agency_network FROM kochava_postbacks.triggers t
   367			LEFT JOIN kochava.cpi_networks n ON n.id = t.filter_network
   368			WHERE t.app_id = ? AND t.type = 'install' AND t.filter_network != '' AND %s
   369		`, agencyScope)
   370	
   371		var triggers []models.Trigger
   372		err := db.db.Raw(query, executeParams...).Scan(&triggers).Error
   373		return triggers, err
   374	}
